%% Per-tick simulation frames fanned out for live demos (grid/agent snapshots and aggregate stats). Broadcast with no queue group so every interested consumer (and the websocket bridge) receives each frame. Default for AGENT_SIM_FRAME_SUBJECT.
%% Service: dd-agent-sim-server
agent_sim_frames_subject() -> <<"dd.remote.agent_sim.frames"/utf8>>.

%% Inbound agent-based / cellular-automata simulation requests consumed by the agent-sim server. Subscribed with the dd-agent-sim-server queue group so requests load-balance across replicas. Default for AGENT_SIM_SIMULATE_SUBJECT.
%% Service: dd-agent-sim-server
agent_sim_simulate_requests_subject() -> <<"dd.remote.agent_sim.simulate.requests"/utf8>>.
agent_sim_simulate_requests_queue_group() -> <<"dd-agent-sim-server"/utf8>>.

%% Final simulation outcomes (final state summary, time series, convergence/extinction flags) emitted after a run completes. Carries an agent_sim.simulate.v1 envelope. Default for AGENT_SIM_RESULT_SUBJECT.
%% Service: dd-agent-sim-server
agent_sim_simulate_results_subject() -> <<"dd.remote.agent_sim.simulate.results"/utf8>>.

%% Emitted when a Merkle root over a posting range is anchored to Solana (tamper-evidence notary). Carries tenant, anchor id, posting range/count, merkle root hex, tx signature, and slot.
%% Service: dd-billing-server
billing_anchors_subject() -> <<"dd.remote.billing.anchors"/utf8>>.

%% Provider-connection lifecycle feed (created, attached/activated, synced, failed). Carries tenant, connection id, provider tag, and the lifecycle transition. No credentials.
%% Service: dd-billing-server
billing_connection_events_subject() -> <<"dd.remote.billing.connections.events"/utf8>>.

%% Emitted after a double-entry transaction is committed to the Postgres ledger. Carries a redacted summary (tenant, transaction id, kind, per-currency totals, posting count) so downstream services can react to ledger movement without reading the database. Default for BILLING_NATS_SUBJECT_LEDGER.
%% Service: dd-billing-server
billing_ledger_postings_subject() -> <<"dd.remote.billing.ledger.postings"/utf8>>.

%% Emitted when a reconciliation break is opened during provider sync (drift between provider-reported state and the ledger). Carries tenant, provider, break type, currency, external ref, and expected/actual minor amounts. Alert-worthy.
%% Service: dd-billing-server
billing_reconciliation_breaks_subject() -> <<"dd.remote.billing.reconciliation.breaks"/utf8>>.

%% Inbound command requesting a provider-connection sync. Payload is {tenantId, connectionId}. Queue-grouped so billing-server replicas load-balance and a given command runs on exactly one pod. Default for BILLING_NATS_SUBJECT_SYNC_COMMANDS.
%% Service: dd-billing-server
billing_sync_commands_subject() -> <<"dd.remote.billing.commands.sync"/utf8>>.
billing_sync_commands_queue_group() -> <<"dd-billing-server"/utf8>>.

%% Redacted provider webhook receipt audit feed. Carries provider, external event id, event type, signature_ok, tenant/connection ids, and the payload sha256 prefix only. The raw webhook body and verification error detail are deliberately NOT published. Mirrors dd.remote.public_data.webhooks.events as an audit source, not a canonical store.
%% Service: dd-billing-server
billing_webhook_receipts_subject() -> <<"dd.remote.billing.webhooks.receipts"/utf8>>.

%% Cross-chain bridge attestations: a source-chain lock confirmed read-only, signalling a transfer is ready for externally-signed destination release. Default for BLOCKCHAIN_BRIDGE_ATTESTATIONS_SUBJECT. Publish-only.
%% Service: dd-contract-service
blockchain_bridge_attestations_subject() -> <<"dd.remote.blockchain.bridge.attestations"/utf8>>.

%% Indexed on-chain references (Solana signatures / EVM tx hashes) emitted by the keyless blockchain indexing module when a watched address is polled. Default for BLOCKCHAIN_INDEX_EVENTS_SUBJECT. Publish-only.
%% Service: dd-contract-service
blockchain_index_events_subject() -> <<"dd.remote.blockchain.index.events"/utf8>>.

%% Monitoring-only MEV/arbitrage spread alerts emitted when an observed venue spread crosses the configured threshold. Default for BLOCKCHAIN_MEV_ALERTS_SUBJECT. Observation surface only; there is no execution path. Publish-only.
%% Service: dd-contract-service
blockchain_mev_alerts_subject() -> <<"dd.remote.blockchain.mev.alerts"/utf8>>.

%% Per-fault lifecycle events (selected, injected, restored, aborted-by-guard) emitted by the chaos loops.
%% Service: dd-chaos
chaos_events_subject() -> <<"dd.remote.chaos.events"/utf8>>.

%% Auditable chaos experiment records: each planned or executed fault (pod-kill, replica-jitter) is published here with its blast radius, target, and dry-run flag.
%% Service: dd-chaos
chaos_experiments_subject() -> <<"dd.remote.chaos.experiments"/utf8>>.

%% Round-trip latency-probe subject. The chaos NATS probe publishes a ping and the same service replies, measuring request/reply RTT and jitter against the live cluster NATS server.
%% Service: dd-chaos
chaos_probe_subject() -> <<"dd.remote.chaos.probe"/utf8>>.
chaos_probe_queue_group() -> <<"dd-chaos-probe"/utf8>>.

